# generated by AI in Github cloud
import unittest
from datetime import date

from hello_world import Greeting, build_output, season_of, time_of_day


class HelloWorldTest(unittest.TestCase):
    def test_greeting_stores_fields(self) -> None:
        greeting = Greeting("World", "Hello")
        self.assertEqual("World", greeting.recipient)
        self.assertEqual("Hello", greeting.message)

    def test_greeting_formatted_contains_recipient_and_message(self) -> None:
        greeting = Greeting("Alice", "Hi")
        result = greeting.formatted()
        self.assertIn("Alice", result)
        self.assertIn("Hi", result)

    def test_greeting_rejects_blank_recipient(self) -> None:
        with self.assertRaises(ValueError):
            Greeting("", "Hello")

    def test_greeting_rejects_blank_message(self) -> None:
        with self.assertRaises(ValueError):
            Greeting("World", " ")

    def test_time_of_day_morning(self) -> None:
        self.assertEqual("morning", time_of_day(0))
        self.assertEqual("morning", time_of_day(11))

    def test_time_of_day_afternoon(self) -> None:
        self.assertEqual("afternoon", time_of_day(12))
        self.assertEqual("afternoon", time_of_day(16))

    def test_time_of_day_evening(self) -> None:
        self.assertEqual("evening", time_of_day(17))
        self.assertEqual("evening", time_of_day(23))

    def test_season_of_returns_correct_values(self) -> None:
        self.assertEqual("Winter", season_of(12))
        self.assertEqual("Winter", season_of(1))
        self.assertEqual("Spring", season_of(3))
        self.assertEqual("Summer", season_of(7))
        self.assertEqual("Autumn", season_of(10))

    def test_build_output_contains_core_values(self) -> None:
        output = build_output(date(2026, 10, 17))
        self.assertIn("Good evening", output)
        self.assertIn("2026-10-17 (Autumn)", output)


if __name__ == "__main__":
    unittest.main()
